groupButton1.onClick:
{{
(async () => {
  if (!appsmith.store.cv_proforma_id) {
    showAlert("Selecciona una proforma para actualizar.", "warning");
    return;
  }

  if (!inpCvProformaNo.text) {
    showAlert("Ingresa el número de proforma.", "warning");
    return;
  }

  if (!(appsmith.store.cv_items_proforma || []).length) {
    showAlert("La proforma debe tener al menos un ítem.", "warning");
    return;
  }

  try {
    await bkCvUpdateProforma.run();
    await bkCvDeleteProformaDetalle.run();
    await bkCvInsertProformaDetalleUpdat.run();

    await qCvProformasResumen.run();
    await qCvOperacionTotales.run();
    await qCvProformaCabecera.run();
    await qCvProformaDetalle.run();

    await storeValue("cv_has_pending_changes", false);

    showAlert("Proforma actualizada correctamente.", "success");
  } catch (err) {
    showAlert("Error al actualizar proforma: " + (err.message || err), "error");
  }
})();
}}

