groupButtonn15izot6di.onClick:
{{
(async () => {
  const row = tblCvProformasResumen.selectedRow;

  if (!row || !row.id) {
    showAlert("Selecciona una proforma para eliminar.", "warning");
    return;
  }

  await storeValue("delete_context", {
    action: "DELETE_CV_PROFORMA",
    id: row.id,
    label: row.proforma_no || row.id,
    message: "Vas a eliminar la proforma " + (row.proforma_no || row.id) + ". Esta acción requiere contraseña."
  });

  resetWidget("inpDeletePassword", true);
  showModal("mdlConfirmDelete");
})();
}}

